<template><div class="auth-page"><section class="auth-card glass-panel"><h1>创建账号</h1><p>注册后即可上传音频、训练个人声线并进行直播TTS。</p><el-form :model="form" label-position="top"><el-form-item label="用户名"><el-input v-model="form.username" size="large" /></el-form-item><el-form-item label="邮箱"><el-input v-model="form.email" size="large" /></el-form-item><el-form-item label="密码"><el-input v-model="form.password" type="password" show-password size="large" /></el-form-item><el-button type="primary" size="large" style="width:100%" :loading="loading" @click="submit">注册</el-button><el-button link style="width:100%;margin-top:10px" @click="$router.push('/login')">已有账号？去登录</el-button></el-form></section></div></template>
<script setup>import { reactive, ref } from 'vue';import { useRouter } from 'vue-router';import { ElMessage } from 'element-plus';import { useUserStore } from '@/stores/user';const router=useRouter(),user=useUserStore(),loading=ref(false);const form=reactive({username:'',email:'',password:''});async function submit(){if(!form.username||!form.password)return ElMessage.warning('请填写用户名和密码');loading.value=true;try{await user.doRegister(form);ElMessage.success('注册成功，请登录');router.push('/login')}finally{loading.value=false}}</script>
